function useVis(th=0.1){const r=useRef(null);const[v,s]=useState(false);useEffect(()=>{const el=r.current;if(!el)return;const o=new IntersectionObserver(([e])=>{if(e.isIntersecting)s(true)},{threshold:th});o.observe(el);return()=>o.disconnect()},[]);return[r,v]}
function R({children,d=0,dir="up",style={}}){const[r,v]=useVis();const t={up:"translateY(32px)",left:"translateX(-32px)",right:"translateX(32px)"};return<div ref={r} style={{opacity:v?1:0,transform:v?"none":t[dir],transition:`opacity .7s cubic-bezier(.16,1,.3,1) ${d}s, transform .7s cubic-bezier(.16,1,.3,1) ${d}s`,...style}}>{children}</div>}
function useTheme(){const[t,s]=useState(()=>localStorage.getItem("gmg-t")||"light");useEffect(()=>{document.documentElement.setAttribute("data-theme",t);localStorage.setItem("gmg-t",t)},[t]);return[t,()=>s(p=>p==="dark"?"light":"dark")]}
function useScrollProgress(ref){const[p,setP]=useState(0);useEffect(()=>{const h=()=>{if(!ref.current)return;const r=ref.current.getBoundingClientRect();const vh=window.innerHeight;setP(Math.max(0,Math.min(1,(vh-r.top)/(vh+r.height))))};addEventListener("scroll",h,{passive:true});h();return()=>removeEventListener("scroll",h)},[]);return p}

function Typer(){const[idx,setIdx]=useState(0);const[text,setText]=useState("");const[del,setDel]=useState(false);useEffect(()=>{const target=D.roles[idx];let timer;if(!del){if(text.length<target.length)timer=setTimeout(()=>setText(target.slice(0,text.length+1)),50);else timer=setTimeout(()=>setDel(true),2200)}else{if(text.length>0)timer=setTimeout(()=>setText(text.slice(0,-1)),25);else{setDel(false);setIdx((idx+1)%D.roles.length)}}return()=>clearTimeout(timer)},[text,del,idx]);return<span style={{color:"var(--acc)"}}>{text}<span style={{display:"inline-block",width:2,height:"1.1em",background:"var(--acc)",marginLeft:2,verticalAlign:"text-bottom",animation:"blink 1s step-end infinite"}}/></span>}
function NameReveal(){const[s,set]=useState(false);useEffect(()=>{setTimeout(()=>set(true),400)},[]);return<h1 style={{fontFamily:"var(--fd)",fontSize:"clamp(60px,12vw,110px)",fontWeight:900,lineHeight:.95,letterSpacing:-5}}><span style={{display:"block",overflow:"hidden"}}>{"Gnana".split("").map((c,i)=><span key={i} style={{display:"inline-block",color:"var(--ink)",opacity:s?1:0,transform:s?"none":"translateY(60px) rotate(8deg)",transition:`all .6s cubic-bezier(.16,1,.3,1) ${.5+i*.06}s`}}>{c}</span>)}</span><span style={{display:"block",overflow:"hidden"}}>{"Ganesh.!".split("").map((c,i)=><span key={i} style={{display:"inline-block",background:"linear-gradient(135deg,var(--acc),#34aadc,#5ac8fa)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",opacity:s?1:0,transform:s?"none":"translateY(60px) rotate(-8deg)",transition:`all .6s cubic-bezier(.16,1,.3,1) ${.8+i*.06}s`}}>{c}</span>)}</span></h1>}
function Particles(){const ref=useRef(null);const pts=useRef([]);const mouse=useRef({x:-999,y:-999});const af=useRef(null);useEffect(()=>{const c=ref.current;const ctx=c.getContext("2d");let W,H;const rs=()=>{W=c.width=c.offsetWidth;H=c.height=c.offsetHeight};rs();addEventListener("resize",rs);for(let i=0;i<50;i++)pts.current.push({x:Math.random()*W,y:Math.random()*H,vx:(Math.random()-.5)*.35,vy:(Math.random()-.5)*.35,r:Math.random()*1.8+.4});const draw=()=>{ctx.clearRect(0,0,W,H);const dk=document.documentElement.getAttribute("data-theme")==="dark";const dc=dk?"41,151,255":"0,113,227";pts.current.forEach(p=>{p.x+=p.vx;p.y+=p.vy;if(p.x<0)p.x=W;if(p.x>W)p.x=0;if(p.y<0)p.y=H;if(p.y>H)p.y=0;const dx=mouse.current.x-p.x,dy=mouse.current.y-p.y,dist=Math.sqrt(dx*dx+dy*dy);const g=dist<200?(200-dist)/200:0;ctx.beginPath();ctx.arc(p.x,p.y,p.r+g*3,0,Math.PI*2);ctx.fillStyle=`rgba(${dc},${.12+g*.6})`;ctx.fill()});pts.current.forEach((p,i)=>{pts.current.slice(i+1).forEach(q=>{const d=Math.sqrt((p.x-q.x)**2+(p.y-q.y)**2);if(d<110){ctx.beginPath();ctx.moveTo(p.x,p.y);ctx.lineTo(q.x,q.y);ctx.strokeStyle=`rgba(${dc},${.05*(1-d/110)})`;ctx.lineWidth=.5;ctx.stroke()}})});af.current=requestAnimationFrame(draw)};draw();const onM=e=>{const r=c.getBoundingClientRect();mouse.current={x:e.clientX-r.left,y:e.clientY-r.top}};c.addEventListener("mousemove",onM);return()=>{removeEventListener("resize",rs);c.removeEventListener("mousemove",onM);cancelAnimationFrame(af.current)}},[]);return<canvas ref={ref} style={{position:"absolute",inset:0,width:"100%",height:"100%",pointerEvents:"auto",zIndex:0}}/>}
function MagneticPhoto(){const[s,set]=useState(false);const[tilt,setTilt]=useState({x:0,y:0});const ref=useRef(null);useEffect(()=>{setTimeout(()=>set(true),200)},[]);const onMove=useCallback(e=>{if(!ref.current)return;const r=ref.current.getBoundingClientRect();const x=(e.clientX-(r.left+r.width/2))/12,y=(e.clientY-(r.top+r.height/2))/12;setTilt({x:Math.max(-15,Math.min(15,y)),y:Math.max(-15,Math.min(15,-x))})},[]);return<div ref={ref} onMouseMove={onMove} onMouseLeave={()=>setTilt({x:0,y:0})} style={{position:"relative",width:180,height:180,marginBottom:28,perspective:600,opacity:s?1:0,transform:s?"scale(1)":"scale(.6)",transition:"opacity .8s cubic-bezier(.16,1,.3,1) .15s, transform .8s cubic-bezier(.16,1,.3,1) .15s"}}><div style={{position:"absolute",inset:-8,borderRadius:"50%",background:"conic-gradient(from 0deg,var(--acc),#5ac8fa,#34aadc,#be5df7,var(--acc))",animation:"spinSlow 3s linear infinite",opacity:s?.5:0,transition:"opacity 1s ease .5s",filter:"blur(4px)"}}/><div style={{width:180,height:180,borderRadius:"50%",overflow:"hidden",border:"4px solid var(--card)",boxShadow:"0 0 50px rgba(0,113,227,.2)",position:"relative",zIndex:1,transform:`rotateX(${tilt.x}deg) rotateY(${tilt.y}deg)`,transition:"transform .15s ease"}}><img src="/img/ganeshhachiko.png" alt="Gnana Ganesh" style={{width:"100%",height:"100%",objectFit:"cover",objectPosition:"center 20%"}}/></div></div>}

