    <R><div style={{textAlign:"center",marginBottom:48}}><p style={{fontFamily:"var(--fm)",fontSize:13,letterSpacing:2,textTransform:"uppercase",color:"var(--acc)",marginBottom:12}}>Projects</p><h2 style={{fontFamily:"var(--fd)",fontSize:"clamp(36px,5.5vw,60px)",fontWeight:900,letterSpacing:-2.5}}><span style={{background:"linear-gradient(90deg,#667eea,#e056a0,#ff6b6b,#ee5a24,#30d158,#0071e3,#667eea)",backgroundSize:"300% 100%",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",animation:"gradientShift 5s ease infinite"}}>Built from scratch.</span></h2></div></R>
